// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, useMap } from "react-leaflet";
import "leaflet/dist/leaflet.css";

/**
 * RainViewer API:
 *  - get frames:  https://tilecache.rainviewer.com/api/maps.json
 *  - tile URL:    https://tilecache.rainviewer.com/v2/radar/{time}/256/{z}/{x}/{y}/2/1_1.png
 */

function RadarLayer({ timestamp }) {
  const map = useMap();
  const layerRef = useRef(null);

  useEffect(() => {
    if (!timestamp) return;

    // Remove previous layer
    if (layerRef.current) {
      map.removeLayer(layerRef.current);
      layerRef.current = null;
    }

    const url = `https://tilecache.rainviewer.com/v2/radar/${timestamp}/256/{z}/{x}/{y}/2/1_1.png`;
    const layer = new window.L.TileLayer(url, {
      opacity: 0.8,
      zIndex: 400,
      maxZoom: 12,
      tileSize: 256,
    });

    layer.addTo(map);
    layerRef.current = layer;

    return () => {
      if (layerRef.current) {
        map.removeLayer(layerRef.current);
        layerRef.current = null;
      }
    };
  }, [timestamp, map]);

  return null;
}

export default function Radar({
  center = [33.749, -84.388],
  zoom = 6,
  height = 320,
  className = "",
}) {
  const [frames, setFrames] = useState([]); // array of { time, past: bool, nowcast: bool }
  const [idx, setIdx] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [showFuture, setShowFuture] = useState(true);

  // fetch frame timestamps
  useEffect(() => {
    let canceled = false;
    async function load() {
      try {
        const res = await fetch("https://tilecache.rainviewer.com/api/maps.json");
        const data = await res.json();
        if (canceled) return;

        // data.past = [...timestamps], data.nowcast = [...timestamps]
        const past = (data?.past || []).map((t) => ({ time: t, type: "past" }));
        const nowc = (data?.nowcast || []).map((t) => ({ time: t, type: "future" }));
        const all = [...past, ...nowc];
        setFrames(all);
        setIdx(all.length - 1); // default to latest
      } catch (e) {
        console.error("RainViewer error:", e);
      }
    }
    load();
    return () => { canceled = true; };
  }, []);

  const visibleFrames = useMemo(
    () => frames.filter((f) => showFuture || f.type !== "future"),
    [frames, showFuture]
  );
  const safeIdx = Math.min(Math.max(idx, 0), Math.max(visibleFrames.length - 1, 0));
  const timestamp = visibleFrames[safeIdx]?.time;

  // autoplay
  useEffect(() => {
    if (!playing || visibleFrames.length === 0) return;
    const id = setInterval(() => {
      setIdx((i) => (i + 1) % visibleFrames.length);
    }, 500);
    return () => clearInterval(id);
  }, [playing, visibleFrames.length]);

  return (
    <div className={`relative w-full ${className}`} style={{ height }}>
      <MapContainer center={center} zoom={zoom} style={{ height: "100%", width: "100%" }}>
        <TileLayer
          attribution='&copy; OpenStreetMap contributors'
          url="https://tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        {timestamp && <RadarLayer timestamp={timestamp} />}
      </MapContainer>

      {/* Controls */}
      <div className="absolute left-2 bottom-2 flex gap-2 items-center rounded-xl bg-black/60 text-white px-3 py-2">
        <button
          className="px-2 py-1 rounded bg-white/10 hover:bg-white/20"
          onClick={() => setPlaying((p) => !p)}
        >
          {playing ? "Pause" : "Play"}
        </button>
        <input
          type="range"
          min={0}
          max={Math.max(visibleFrames.length - 1, 0)}
          value={safeIdx}
          onChange={(e) => setIdx(parseInt(e.target.value, 10))}
        />
        <label className="flex items-center gap-1 text-xs">
          <input
            type="checkbox"
            checked={showFuture}
            onChange={(e) => setShowFuture(e.target.checked)}
          />
          Forecast
        </label>
      </div>
    </div>
  );
}
